import{_ as e,o as a,c as l,a2 as r}from"./chunks/framework.BQ1gajhD.js";const x=JSON.parse('{"title":"八达岭长城","description":"","frontmatter":{},"headers":[],"relativePath":"landmarks/badaling.md","filePath":"landmarks/badaling.md","lastUpdated":null}'),n={name:"landmarks/badaling.md"};function d(o,t,i,s,h,g){return a(),l("div",null,[...t[0]||(t[0]=[r('<h1 id="八达岭长城" tabindex="-1">八达岭长城 <a class="header-anchor" href="#八达岭长城" aria-label="Permalink to &quot;八达岭长城&quot;">​</a></h1><blockquote><p>&quot;不到长城非好汉，屈指行程二万。&quot; —— 毛泽东《清平乐·六盘山》</p></blockquote><h2 id="简介" tabindex="-1">简介 <a class="header-anchor" href="#简介" aria-label="Permalink to &quot;简介&quot;">​</a></h2><p>八达岭长城位于北京市延庆区，是万里长城的重要组成部分，也是明长城向游客开放最早的地段。八达岭长城地势险要，城关坚固，是扼守京北的咽喉要道，自古就是军事战略要地。</p><h2 id="基本信息" tabindex="-1">基本信息 <a class="header-anchor" href="#基本信息" aria-label="Permalink to &quot;基本信息&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">项目</th><th style="text-align:left;">内容</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>开放时间</strong></td><td style="text-align:left;">6:30-16:30（随季节调整）</td></tr><tr><td style="text-align:left;"><strong>门票价格</strong></td><td style="text-align:left;">旺季40元，淡季35元；索道往返140元</td></tr><tr><td style="text-align:left;"><strong>建议游玩</strong></td><td style="text-align:left;">3-4小时</td></tr><tr><td style="text-align:left;"><strong>最佳季节</strong></td><td style="text-align:left;">春秋两季，秋季红叶最美</td></tr><tr><td style="text-align:left;"><strong>交通方式</strong></td><td style="text-align:left;">877路公交、S2线火车或自驾</td></tr><tr><td style="text-align:left;"><strong>预约方式</strong></td><td style="text-align:left;">八达岭长城官方微信公众号预约</td></tr></tbody></table><h2 id="历史沿革" tabindex="-1">历史沿革 <a class="header-anchor" href="#历史沿革" aria-label="Permalink to &quot;历史沿革&quot;">​</a></h2><h3 id="修建历史" tabindex="-1">修建历史 <a class="header-anchor" href="#修建历史" aria-label="Permalink to &quot;修建历史&quot;">​</a></h3><p>八达岭长城始建于明弘治十八年（1505年），是明代长城中保存最完好、最具代表性的一段。嘉靖、万历年间多次修缮加固。</p><h3 id="历史地位" tabindex="-1">历史地位 <a class="header-anchor" href="#历史地位" aria-label="Permalink to &quot;历史地位&quot;">​</a></h3><p>八达岭是居庸关的重要前哨，地势居高临下，古人称之为&quot;居庸之险不在关而在八达岭&quot;。这里自古就是兵家必争之地，发生过无数次激烈战斗。</p><h3 id="开放历史" tabindex="-1">开放历史 <a class="header-anchor" href="#开放历史" aria-label="Permalink to &quot;开放历史&quot;">​</a></h3><p>1953年修复并向公众开放，是万里长城最早向游客开放的地段。1987年被列入《世界遗产名录》。</p><h2 id="建筑特色" tabindex="-1">建筑特色 <a class="header-anchor" href="#建筑特色" aria-label="Permalink to &quot;建筑特色&quot;">​</a></h2><h3 id="城墙结构" tabindex="-1">城墙结构 <a class="header-anchor" href="#城墙结构" aria-label="Permalink to &quot;城墙结构&quot;">​</a></h3><p>八达岭长城城墙平均高7.8米，上宽5.8米，可容五马并骑，十人并行。城墙用巨大的条石和城砖砌成，坚固异常。</p><h3 id="敌楼设置" tabindex="-1">敌楼设置 <a class="header-anchor" href="#敌楼设置" aria-label="Permalink to &quot;敌楼设置&quot;">​</a></h3><p>沿墙每隔约100米设有一座敌楼，可供士兵驻守、瞭望、储存武器。敌楼分为两层：上层供士兵驻守瞭望，下层储存武器和粮食。</p><h3 id="关城布局" tabindex="-1">关城布局 <a class="header-anchor" href="#关城布局" aria-label="Permalink to &quot;关城布局&quot;">​</a></h3><p>八达岭关城为东窄西宽的梯形，有东西二门。东门额题&quot;居庸外镇&quot;，西门额题&quot;北门锁钥&quot;。关城内有翁城、垛口、射孔等防御设施。</p><h2 id="游览区域" tabindex="-1">游览区域 <a class="header-anchor" href="#游览区域" aria-label="Permalink to &quot;游览区域&quot;">​</a></h2><h3 id="北线-北一到北十二楼" tabindex="-1">北线（北一到北十二楼） <a class="header-anchor" href="#北线-北一到北十二楼" aria-label="Permalink to &quot;北线（北一到北十二楼）&quot;">​</a></h3><p>北线坡度较陡，其中北八楼是八达岭长城的最高点（海拔888米），也是游客最集中的地方。从北八楼往后，游人渐少，可以体验更原始的长城风貌。</p><p><strong>推荐程度</strong>：⭐⭐⭐⭐⭐ <strong>难度</strong>：中等偏难 <strong>特点</strong>：风景最佳，挑战性强</p><h3 id="南线-南一到南七楼" tabindex="-1">南线（南一到南七楼） <a class="header-anchor" href="#南线-南一到南七楼" aria-label="Permalink to &quot;南线（南一到南七楼）&quot;">​</a></h3><p>南线相对平缓，坡度较小，适合体力一般或带老人小孩的游客。南四楼附近有好汉坡，是拍照打卡的好地方。</p><p><strong>推荐程度</strong>：⭐⭐⭐⭐ <strong>难度</strong>：容易 <strong>特点</strong>：人流较少，轻松游览</p><h2 id="文化故事" tabindex="-1">文化故事 <a class="header-anchor" href="#文化故事" aria-label="Permalink to &quot;文化故事&quot;">​</a></h2><h3 id="不到长城非好汉" tabindex="-1">&quot;不到长城非好汉&quot; <a class="header-anchor" href="#不到长城非好汉" aria-label="Permalink to &quot;&quot;不到长城非好汉&quot;&quot;">​</a></h3><p>1935年10月，中央红军长征到达六盘山，毛泽东在此写下《清平乐·六盘山》，其中&quot;不到长城非好汉&quot;一句，使长城成为中华民族精神的象征。</p><h3 id="孟姜女哭长城" tabindex="-1">孟姜女哭长城 <a class="header-anchor" href="#孟姜女哭长城" aria-label="Permalink to &quot;孟姜女哭长城&quot;">​</a></h3><p>民间传说中，孟姜女的丈夫被征去修长城，累死并被埋在长城下。孟姜女千里寻夫，哭倒长城八百里。虽然这是传说，但反映了古代劳动人民修建长城的艰辛。</p><h3 id="烽火传警" tabindex="-1">烽火传警 <a class="header-anchor" href="#烽火传警" aria-label="Permalink to &quot;烽火传警&quot;">​</a></h3><p>古代长城上设有烽火台，白天燃烟、夜晚举火传递军情。据说一天之内可以将消息传到千里之外的京城。</p><h2 id="游览攻略" tabindex="-1">游览攻略 <a class="header-anchor" href="#游览攻略" aria-label="Permalink to &quot;游览攻略&quot;">​</a></h2><h3 id="推荐路线" tabindex="-1">推荐路线 <a class="header-anchor" href="#推荐路线" aria-label="Permalink to &quot;推荐路线&quot;">​</a></h3><p><strong>经典路线（约3-4小时）</strong>：</p><p>登城口 → 北一楼 → 北四楼 → 北七楼 → 北八楼（最高点） → 北十一楼 → 北十二楼 → 下山</p><p><strong>轻松路线（约2小时）</strong>：</p><p>缆车/滑道至北四楼 → 北五楼 → 北六楼 → 北七楼 → 北八楼 → 缆车下山</p><h3 id="交通方式" tabindex="-1">交通方式 <a class="header-anchor" href="#交通方式" aria-label="Permalink to &quot;交通方式&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">方式</th><th style="text-align:left;">路线</th><th style="text-align:center;">时间</th><th style="text-align:center;">费用</th></tr></thead><tbody><tr><td style="text-align:left;">公交</td><td style="text-align:left;">德胜门乘877路直达</td><td style="text-align:center;">约1.5小时</td><td style="text-align:center;">12元</td></tr><tr><td style="text-align:left;">火车</td><td style="text-align:left;">黄土店乘S2线至八达岭</td><td style="text-align:center;">约80分钟</td><td style="text-align:center;">7元</td></tr><tr><td style="text-align:left;">自驾</td><td style="text-align:left;">京藏高速八达岭出口</td><td style="text-align:center;">约1小时</td><td style="text-align:center;">-</td></tr><tr><td style="text-align:left;">旅游专线</td><td style="text-align:left;">前门、天安门发车</td><td style="text-align:center;">约2小时</td><td style="text-align:center;">80元</td></tr></tbody></table><h3 id="实用贴士" tabindex="-1">实用贴士 <a class="header-anchor" href="#实用贴士" aria-label="Permalink to &quot;实用贴士&quot;">​</a></h3><ol><li><strong>提前预约</strong>：必须提前在微信公众号预约门票，现场不售票</li><li><strong>避开高峰</strong>：周末和节假日人极多，建议工作日前往</li><li><strong>穿着建议</strong>：穿舒适运动鞋，部分路段很陡</li><li><strong>携带物品</strong>：带足水（山上水贵），带防风外套（山顶风大）</li><li><strong>最佳时间</strong>：早上7:30前或下午3:00后，避开人流高峰</li><li><strong>缆车选择</strong>：体力不佳者可乘缆车（单程100元，往返140元）</li></ol><h2 id="周边景点" tabindex="-1">周边景点 <a class="header-anchor" href="#周边景点" aria-label="Permalink to &quot;周边景点&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">景点</th><th style="text-align:center;">距离</th><th style="text-align:left;">特色</th></tr></thead><tbody><tr><td style="text-align:left;">明十三陵</td><td style="text-align:center;">约20公里</td><td style="text-align:left;">明朝皇帝陵墓群</td></tr><tr><td style="text-align:left;">居庸关</td><td style="text-align:center;">约10公里</td><td style="text-align:left;">&quot;天下第一雄关&quot;</td></tr><tr><td style="text-align:left;">水关长城</td><td style="text-align:center;">约5公里</td><td style="text-align:left;">人少清净</td></tr><tr><td style="text-align:left;">八达岭野生动物园</td><td style="text-align:center;">约3公里</td><td style="text-align:left;">可自驾游览</td></tr></tbody></table><hr><p><strong>📍 地址</strong>：北京市延庆区G6京藏高速58号出口 <strong>📞 电话</strong>：010-69121383 <strong>🌐 官网</strong>：<a href="http://www.badaling.cn" target="_blank" rel="noreferrer">www.badaling.cn</a></p>',48)])])}const b=e(n,[["render",d]]);export{x as __pageData,b as default};
